INSERT INTO public.photos VALUES (23549, 'Pedro Santisteve 1990', 'Pedro Santisteve (Zaragoza, 1958), abogado penalista y alcalde de Zaragoza desde 2015, sustituyendo a Juan Alberto Belloch (2003-2015). En la imagen, en el bar La Vâ”œÂ¡a Lâ”œÃ­ctea (Doctor Palomar 25) en 1990. Fuente: Asociaciâ”œâ”‚n Cultural y Recreativa Barrio Verde de Zaragoza.', 1990, 1990, 1990, 'Anos 90', 'CASCO HISTâ”œÃ´RICO', 41.65113200, -0.87187600, '0101000020E61000007D5A457F68E6EBBF85B01A4B58D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19065572706.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19065572706.webp', 'https://www.flickr.com/photos/zaragozaantigua/19065572706/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23550, 'Calle Mayor 1847', 'Dibujo de Josâ”œÂ® Gâ”œâ”‚mez Piquer de 1997, recreando el rincâ”œâ”‚n de la calle Mayor nâ”¬â•‘ 59 (a la izquierda, fuera de la imagen) donde fue instalada la Escuela Profesional de Veterinaria de Zaragoza en 1847, y hasta 1853. En las inmediaciones, en la esquina de la calle de Torrejâ”œâ”‚n con Mayor, hoy sede del PCE en Aragâ”œâ”‚n, tuvo su sede el Colegio de Nuestra Seâ”œâ–’ora del Torrejâ”œâ”‚n, colegio mayor universitario seglar fundado en 1602 y clausurado a mediados del siglo XIX. El dibujo supone la torre de la iglesia de La Magdalena sin su recrecimiento barroco, que sâ”œÂ¡ estaba en la fecha que se intenta reflejar. Fuente: Crâ”œâ”‚nica de 150 aâ”œâ–’os de estudios veterinarios en Aragâ”œâ”‚n. IFC, 2000.', 1847, 1847, 1847, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65244800, -0.87403700, '0101000020E610000074CE4F711CF8EBBF992B836A83D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19115291828.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19115291828.webp', 'https://www.flickr.com/photos/zaragozaantigua/19115291828/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23551, 'Coso Bajo 1984', 'Foto Arturo Burgos, 1984. Calle del Coso Bajo de Zaragoza en 1984, con visual de sus nâ”œâ•‘meros pares en el tramo comprendido entre las plazas de La Magdalena y las Tenerâ”œÂ¡as. Fuente: Zaragoza, sus calles y su historia, 1984.', 1984, 1984, 1984, 'Anos 80', 'CASCO HISTâ”œÃ´RICO', 41.65240800, -0.87278000, '0101000020E6100000CB4A9352D0EDEBBF0BD3F71A82D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19428864662.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19428864662.webp', 'https://www.flickr.com/photos/zaragozaantigua/19428864662/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23553, 'Plaza de la Magdalena 1960', 'Imagen del funeral, el 19 de octubre de 1960, de Carmelo Zaldâ”œÂ¡var, jefe de administraciâ”œâ”‚n del Ayuntamiento de Zaragoza. La comitiva se dirige, desde la calle Mayor, a la puerta de la iglesia de la Magdalena. En el lateral del templo se observa la capilla exterior adosada dedicada a San Cristâ”œâ”‚bal, como el arco que tenâ”œÂ¡a enfrente en la calle del mismo nombre. AL fondo de la calle, el mercado de San Vicente de Paâ”œâ•‘l, recayente a la vâ”œÂ¡a del mismo nombre. Fuente: AMZ.', 1960, 1960, 1960, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65236800, -0.87371300, '0101000020E6100000ACE122F774F5EBBF7D7A6CCB80D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20466773353.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20466773353.webp', 'https://www.flickr.com/photos/zaragozaantigua/20466773353/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23554, 'Calle del â”œÃ´rgano 1989', 'La calle del â”œÃ´rgano el 17 de febrero de 1989, en las traseras de la iglesia de La Magdalena, que debe su nombre al receptâ”œÃ­culo de ese instrumento, que forma un pasadizo o arco sobre la vâ”œÂ¡a. En primer plano, el pilâ”œâ”‚n de piedra ya desaparecido, como casi todos los de su entorno. La imagen estâ”œÃ­ tomada desde la calle Mayor, con la de Martâ”œÂ¡n Carrillo al fondo. Fuente: "Memoria de las calles de Zaragoza", Juliâ”œÃ­n Ruiz Marâ”œÂ¡n, Librerâ”œÂ¡a General, 2002.', 1989, 1989, 1989, 'Anos 80', 'CASCO HISTâ”œÃ´RICO', 41.65244800, -0.87403700, '0101000020E610000074CE4F711CF8EBBF992B836A83D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21053815984.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21053815984.webp', 'https://www.flickr.com/photos/zaragozaantigua/21053815984/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23557, 'Calle de Olleta 1967', 'Calle de Jusepillo de Olleta en 1967. Comienza en la de San Agustâ”œÂ¡n y termina en la de las Arcadas. La imagen estâ”œÃ­ capturada justo antes de que la calle Barrioverde cruce la calle Olleta, ascendente y adoquinada de izquierda a derecha. Al fondo, a la izquierda, se deriva la calle de Luzâ”œÃ­n. Fuente visual: Foto Leonardo Pâ”œÂ®rez Obis, donada por â”œÃ¼ngel Hernâ”œÃ­ndez Mostajo para www.rafaelcastillejo.com', 1967, 1967, 1967, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65219900, -0.87368200, '0101000020E6100000EB5223F433F5EBBFF1BDBF417BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22728082717.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22728082717.webp', 'https://www.flickr.com/photos/zaragozaantigua/22728082717/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23560, 'Calle San Cristâ”œâ”‚bal 1965', 'Insâ”œâ”‚lita imagen, posiblemente de la antigua plazuela de Juan del Corral, como ensanche de la calleja de San Cristâ”œâ”‚bal de la Magdalena, que conectaba la calle de San Lorenzo, al fondo, con la calle Mayor, en este caso bajo un arquitrabado arco nominado tambiâ”œÂ®n "de San Cristâ”œâ”‚bal". De ser asâ”œÂ¡, esta plazuela tendrâ”œÂ¡a relaciâ”œâ”‚n con el lugar donde estuvo la casa solariega de esta familia infanzona de caballeros hidalgos, apellidados del Corral, o Ximâ”œÂ®nez del Corral, que se establecieron en la ciudad en el siglo XVII. Unos aâ”œâ–’os despuâ”œÂ®s de esta captura fotogrâ”œÃ­fica, el entorno edificatorio fue bastante transformado, aunque la plazuela mantiene su planta de "quesito" (mâ”œÃ­s o menos). Fuente visual: Foto Leonardo Pâ”œÂ®rez Obis, donada por â”œÃ¼ngel Hernâ”œÃ­ndez Mostajo para www.rafaelcastillejo.com', 1965, 1965, 1965, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65212200, -0.87414100, '0101000020E6100000B1F7E28BF6F8EBBF4580D3BB78D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22758258227.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22758258227.webp', 'https://www.flickr.com/photos/zaragozaantigua/22758258227/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23561, 'Calle Olleta 1967', 'Calle de Jusepillo de Olleta en 1967. Comienza en la de San Agustâ”œÂ¡n y termina en la de las Arcadas. Hoy radicalmente transformada. La imagen estâ”œÃ­ capturada, precisamente, donde la calle Olleta desembocaba en la calle de las Arcadas, cuyo antiguo (y desaparecido) azulejo nâ”œâ•‘mero 21, bajo el de la aseguradora de incendios, referencia el lugar. Los tendedores con cuerda, y una prenda a secar, seâ”œâ–’ales de moradores. Fuente visual: Foto Leonardo Pâ”œÂ®rez Obis, donada por â”œÃ¼ngel Hernâ”œÃ­ndez Mostajo para www.rafaelcastillejo.com', 1967, 1967, 1967, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65219900, -0.87187900, '0101000020E6100000C136E2C96EE6EBBFF1BDBF417BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22826932950.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22826932950.webp', 'https://www.flickr.com/photos/zaragozaantigua/22826932950/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23565, 'Coso Bajo 1986', 'Imagen capturada en el Coso Bajo y centrada en el tramo de los antiguos y dispares nâ”œâ•‘meros impares entre la calle de San Lorenzo (izquierda) y la plaza de la Magdalena (a la derecha, fuera de plano). Este tramo serâ”œÂ¡a profundamente remodelado aâ”œâ–’os despuâ”œÂ®s. Fuente visual: AMZ.', 1986, 1986, 1986, 'Anos 80', 'CASCO HISTâ”œÃ´RICO', 41.65182500, -0.87363700, '0101000020E6100000EC6AF294D5F4EBBF8CDB68006FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24834862868.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24834862868.webp', 'https://www.flickr.com/photos/zaragozaantigua/24834862868/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23566, 'Plaza de la Magdalena 1960', 'Imagen, desde cierta altura, de la sesentera plaza de la Magdalena durante el funeral de Carmelo Zaldâ”œÂ¡var, jefe de administraciâ”œâ”‚n del Ayuntamiento. A la izquierda, la calle Mayor. En el centro, la iglesia parroquial de Santa Marâ”œÂ¡a Magdalena, funcional, y con el remate barroco de la torre. A la derecha, el edificio de la antigua Universidad Literaria (hasta 1958 sede del Instituto Goya), y el que fuera colegio de San Juan Bautista. Por encima, despuntan dos torres pilaristas. Fuente visual: Archivo Municipal de Zaragoza.', 1960, 1960, 1960, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65223900, -0.87360700, '0101000020E610000042D0D1AA96F4EBBF7F164B917CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25499727161.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25499727161.webp', 'https://www.flickr.com/photos/zaragozaantigua/25499727161/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23568, 'Pl. de San Agustâ”œÂ¡n 1991', 'Imagen parcial de la plaza de San Agustâ”œÂ¡n capturada desde el final de la calle Viola, con vista del espacio donde desembocan las calles de San Agustâ”œÂ¡n y de las Arcadas. A la derecha, parte del antiguo convento y cuartel de San Agustâ”œÂ¡n que luego serâ”œÂ¡a reformada para acoger la biblioteca municipal Marâ”œÂ¡a Moliner. Fuente visual: AMZ.', 1991, 1991, 1991, 'Anos 90', 'CASCO HISTâ”œÃ´RICO', 41.65116000, -0.87126600, '0101000020E61000004DBC033C69E1EBBF4F3BFC3559D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28318398369.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28318398369.webp', 'https://www.flickr.com/photos/zaragozaantigua/28318398369/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23569, 'Calle Martâ”œÂ¡n Carrillo aâ”œâ–’os 30', 'Acuarela de Ambrosio Ruste representando la calle de Martâ”œÂ¡n Carrillo, con la iglesia de la Magdalena a la derecha y la plaza homâ”œâ”‚nima al fondo. Fuente: Lâ”œÃ­minas de A. Ruste. Ayuntamiento de Zaragoza, 1977.', 1930, 1930, 1939, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65255000, -0.87373700, '0101000020E6100000CEC3094CA7F5EBBF9D8026C286D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31595527374.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31595527374.webp', 'https://www.flickr.com/photos/zaragozaantigua/31595527374/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23573, 'Pl. Magdalena 1931', 'Foto: Miguel Marâ”œÂ¡n Chivite. "Animado aspecto de las puertas del colegio electoral instalado en la Universidad, durante la maâ”œâ–’ana del domingo" 12 de abril de 1931, dâ”œÂ¡a de las elecciones municipales, cuyo resultado determinâ”œâ”‚ la llegada de la Segunda Repâ”œâ•‘blica dos dâ”œÂ¡as despuâ”œÂ®s. Fuente: Heraldo de Aragâ”œâ”‚n.', 1931, 1931, 1931, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65218900, -0.87338300, '0101000020E61000005C3CBCE7C0F2EBBFCDE7DCED7AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31898187726.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31898187726.webp', 'https://www.flickr.com/photos/zaragozaantigua/31898187726/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23574, 'Plaza de la Universidad c.1929', 'Imagen de la monumental escalera de la antigua Universidad Literaria de la Magdalena. Esta fue una de las destacadas piezas que Ricardo Magdalena dio nuevo empaque en la gran reforma acometida entre 1907-1912. De 1925 es el elemento que centraliza la imagen, una lâ”œÃ­pida que fue inaugurada durante la Dictadura de Primo de Rivera, con presencia del rey Alfonso XIII, en homenaje a los estudiantes valencianos muertos en los asedios de Zaragoza en 1808-1809. Cuando en 1967 este lugar fue derribado, la lâ”œÃ­pida fue demediada y reinstalada sin atributos identificativos en un insâ”œâ”‚lito establecimiento de la ciudad. Oficialmente se la dio por desaparecida, de forma que la lâ”œÃ­pida que hoy se encuentra en el actual Paraninfo de la plaza de Paraâ”œÂ¡so es una reproducciâ”œâ”‚n de la lâ”œÃ­pida que, sobre el mismo asunto, fue inaugurada en 1924 en la Universidad de Valencia. Parece enrevesado, aunque tal vez sâ”œâ”‚lo sea que Zaragoza tiene complejas sinuosidades que fluyen en el mar de fondo de su acontecer histâ”œâ”‚rico, bajo una engaâ”œâ–’osa apariencia de simplicidad. Fuente visual: foto Juan Mora Insa, en elblogdezaragoza.blogspot.com.es/', 1929, 1929, 1929, 'Anos 20', 'CASCO HISTâ”œÃ´RICO', 41.65283500, -0.87293900, '0101000020E6100000EBE40CC51DEFEBBF9357E71890D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32214302646.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32214302646.webp', 'https://www.flickr.com/photos/zaragozaantigua/32214302646/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23576, 'Coso Bajo 1814', '"Entrada triunfal de Fernando VII en Zaragoza". â”œÃ´leo sobre lienzo, Miguel Parra Abril, 1818. La escena representa la visita de Fernando VII a Zaragoza, el 6 de abril de 1814. La comitiva estaba formada tambiâ”œÂ®n por su hermano Carlos Marâ”œÂ¡a Isidro, el duque de San Carlos y Josâ”œÂ® Palafox. Entraron por el puente de Piedra, siguieron por las Tenerâ”œÂ¡as, pasaron por la plaza de la Magdalena y subieron por el Coso hasta llegar al palacio de Sâ”œÃ­stago. El rey estuvo en Zaragoza hasta el 11 de abril. El escenario escogido para el cuadro es el tramo del Coso Bajo con las simbâ”œâ”‚licas ruinas del seminario, tomando como modelo el grabado de Gâ”œÃ­lvez y Brambila de 1814 "Ruinas del Seminario". Se trata del edifico que se ve al fondo, entre las calles de San Jorge y San Lorenzo. Fuente visual: Palacio Real de Madrid.', 1814, 1814, 1814, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65158800, -0.87421900, '0101000020E61000009F56D11F9AF9EBBFA73B4F3C67D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32856669552.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32856669552.webp', 'https://www.flickr.com/photos/zaragozaantigua/32856669552/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23578, 'Universidad Literaria c.1929', 'Imagen capturada en el descansillo de la monumental escalera de la Universidad Literaria de la Magdalena, una de las destacadas piezas que Ricardo Magdalena habâ”œÂ¡a reformado en 1907-1912 dâ”œÃ­ndole este imponente aspecto. En la planta baja, acceso desde el vestâ”œÂ¡bulo recayente a la plaza de la Magdalena y ventanas a la galerâ”œÂ¡a del patio de luces. Toda esta zona quedâ”œâ”‚ convertida en un campo de cascotes cuando el edificio fue derribado a finales de la prodigiosa dâ”œÂ®cada de los aâ”œâ–’os sesenta, que terminaron depositados en uno de los abundantes vertederos de escombros que jalonaban la periferia de una ciudad ensimismada en la modernidad y progreso. Fuente visual: foto Juan Mora Insa, en elblogdezaragoza.blogspot.com.es/', 1929, 1929, 1929, 'Anos 20', 'CASCO HISTâ”œÃ´RICO', 41.65218900, -0.87338300, '0101000020E61000005C3CBCE7C0F2EBBFCDE7DCED7AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34922119006.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34922119006.webp', 'https://www.flickr.com/photos/zaragozaantigua/34922119006/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23580, 'Calle del Râ”œÂ¡o 1986', 'Imagen capturada desde el solar de los antiguos talleres y almacenes municipales de la Rebolerâ”œÂ¡a y centrada en los edificios de vivienda de los antiguos nâ”œâ•‘meros 16, 18, 29 y 22 de la calle del Râ”œÂ¡o. A la derecha, ingreso al callejâ”œâ”‚n del Râ”œÂ¡o. A la izquierda, esquinero y moderno bloque del nâ”¬â•‘ 18 de la calle Monreal. Aâ”œâ–’os despuâ”œÂ®s, estos inmuebles serâ”œÂ¡an derribados y sustituidos por el moderno bloque del nâ”¬â•‘ 18 de la calle del Râ”œÂ¡o. Justo enfrente serâ”œÂ¡a construido otro nuevo bloque correspondiente a los actuales nâ”¬â•‘ 7, 9 y 11 de la misma calle, junto al CEIP (Colegio Pâ”œâ•‘blico de Educaciâ”œâ”‚n Infantil y Primaria) y al Pabellâ”œâ”‚n Deportivo Municipal Tenerâ”œÂ¡as. Fuente visual: AMZ.', 1986, 1986, 1986, 'Anos 80', 'CASCO HISTâ”œÃ´RICO', 41.65343700, -0.87010700, '0101000020E610000058A9A0A2EAD7EBBF887FD8D2A3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/37743144235.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/37743144235.webp', 'https://www.flickr.com/photos/zaragozaantigua/37743144235/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23581, 'Iglesia Magdalena c.1966', 'Vista de la iglesia de Santa Marâ”œÂ¡a Magdalena cuando comienzan a desmocharle la torre para devolverle el probable aspecto original, eliminando su remate barroco.', 1966, 1966, 1966, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65253300, -0.87391700, '0101000020E6100000CC63CDC820F7EBBFC7478B3386D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38037597074.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38037597074.webp', 'https://www.flickr.com/photos/zaragozaantigua/38037597074/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23582, 'Coso Bajo 1986', 'Imagen capturada en el Coso Bajo y centrada en los solares y antiguos edificios correspondientes a los nâ”œâ•‘meros 170, 172 y 174 del Coso, y el nâ”œâ•‘mero 5 del arranque de la calle de San Agustâ”œÂ¡n (a la derecha). Desde finales de la dâ”œÂ®cada siguiente estos inmuebles serâ”œÂ¡an derribados y sobre sus solares se levantarâ”œÂ¡an las actuales viviendas que allâ”œÂ¡ se ubican. Al fondo, a la derecha, el nâ”¬â•‘ 2 de la calle de Jusepillo Olleta. Fuente visual: AMZ.', 1986, 1986, 1986, 'Anos 80', 'CASCO HISTâ”œÃ´RICO', 41.65204200, -0.87292900, '0101000020E6100000075C57CC08EFEBBF29CFBC1C76D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38580739381.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38580739381.webp', 'https://www.flickr.com/photos/zaragozaantigua/38580739381/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23583, 'Coso Bajo 1986', 'Imagen capturada en el Coso Bajo y centrada en los antiguos edificios (de finales del siglo XIX) correspondientes a los nâ”œâ•‘meros 174 (parcial), 176, 178 y 180, esquinero con el arranque de la calle de Alcober, de la que se muestran las fachadas de los nâ”œâ•‘meros 1, 3 y 5. De todos ellos perdura el nâ”œâ•‘mero 180. El resto fueron luego derribados, bien para dar paso a modernas construcciones habitacionales (actual nâ”œâ•‘mero 174), bien para "esponjar" esta zona ubicada entra las plazas de la Magdalena, Tenerâ”œÂ¡as, y San Agustâ”œÂ¡n mediante un solar habilitado para uso pâ”œâ•‘blico (esquina Alcober-Coso). Fuente visual: AMZ.', 1986, 1986, 1986, 'Anos 80', 'CASCO HISTâ”œÃ´RICO', 41.65241900, -0.87253200, '0101000020E6100000C3D4963AC8EBEBBFFF243E7782D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38639236771.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38639236771.webp', 'https://www.flickr.com/photos/zaragozaantigua/38639236771/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23584, 'Convento de San Agustâ”œÂ¡n 1809', 'Imagen del costumbrista â”œâ”‚leo sobre lienzo &quot;Heroica defensa de la torre de San Agustâ”œÂ¡n en Zaragoza en la Guerra de la Independencia&quot; pintado por Câ”œÂ®sar â”œÃ¼lvarez Dumont en 1884, posiblemente basado en el Episodio Nacional de Benito Pâ”œÂ®rez Galdâ”œâ”‚s, &quot;Zaragoza&quot;. Los verâ”œÂ¡dicos hechos referidos sucedieron durante el segundo asedio de la ciudad por las tropas francesas, en febrero de 1809. El â”œâ”‚leo centra la atenciâ”œâ”‚n en el interior de la torre del convento de San Agustâ”œÂ¡n y unos peleones paisanos dispuestos en colorista y triangular composiciâ”œâ”‚n que culmina en la campana de la torre. A la izquierda, una gran bota de vino y varios grafitis patriâ”œâ”‚ticos en la pared, entre los que destacan &quot;gabacho&quot;, despectiva denominaciâ”œâ”‚n del francâ”œÂ®s desde el siglo XVII y &quot;Pepe Botella&quot;, capciosa referencia al rey Josâ”œÂ® I Bonaparte. Fuente visual: www.museodelprado.es', 1809, 1809, 1809, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65090300, -0.87077200, '0101000020E61000006BB8C83D5DDDEBBF24EF1CCA50D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/39937575692.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/39937575692.webp', 'https://www.flickr.com/photos/zaragozaantigua/39937575692/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23585, 'Calle de San Cristâ”œâ”‚bal c.1965', 'Imagen capturada en la antigua calle de San Cristâ”œâ”‚bal con una interesante vista parcial de la torre de la iglesia parroquial de la Magdalena emergiendo entre antiguas viviendas de la calle Mayor, construidas en el siglo XVI y muy reformadas en el XIX. El remate de la torre seguâ”œÂ¡a siendo el tradicional desde â”œÂ®poca barroca. Fuente visual: foto Palacio, AMZ.', 1965, 1965, 1965, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65225800, -0.87401200, '0101000020E61000003CF88903E8F7EBBFF646AD307DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40580927171.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40580927171.webp', 'https://www.flickr.com/photos/zaragozaantigua/40580927171/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23586, 'Calle de Josâ”œÂ® Palafox 1991', 'Imagen centrada en el solar conformado tras el derribo del nâ”¬â•‘ 31 de la calle de Josâ”œÂ® Palafox (tramo antiguamente denominado de San Vicente) y el nâ”¬â•‘ 15 de la calle Universidad (antigua de la Trinidad), tras una transitoria y colorista remodelaciâ”œâ”‚n hasta que se llevara a cabo el correspondiente desarrollo urbanâ”œÂ¡stico. Este solar lindaba, a la izquierda, con el antiguo Laboratorio Quâ”œÂ¡mico Municipal construido en 1914 segâ”œâ•‘n proyecto del arquitecto municipal Josâ”œÂ® de Yarza Echenique. A la derecha, los nâ”œâ•‘meros 16 y 14 de la calle de Don Teobaldo, construidos en la dâ”œÂ®cada de los aâ”œâ–’os treinta, y fachada del convento de las Canonesas Regulares del Santo Sepulcro. Pocos aâ”œâ–’os despuâ”œÂ®s, sobre este solar serâ”œÂ¡a construido el actual nâ”¬â•‘ 18 de la calle de Don Teobaldo. Fuente visual: AMZ.', 1991, 1991, 1991, 'Anos 90', 'CASCO HISTâ”œÃ´RICO', 41.65328400, -0.87295000, '0101000020E6100000E561A1D634EFEBBF028063CF9ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/42332210674.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/42332210674.webp', 'https://www.flickr.com/photos/zaragozaantigua/42332210674/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23587, 'Calle de Alonso V 1986', 'Imagen capturada en la calle de Alonso V y centrada en el tramo de los inmuebles de los nâ”œâ•‘meros 6-12 (de derecha a izquierda), adosados desde finales del siglo XIX sobre la muralla medieval de ladrillo que delimitaba la ciudad en esta zona, dejando extramuros a la rebolerâ”œÂ¡a, al otro lado de la entonces calle de las Tenerâ”œÂ¡as. El estrechisimo inmueble del nâ”¬â•‘ 8, a la derecha del â”œÃ­rbol de la escena, se correspondâ”œÂ¡a con uno de los antiguos torreones que desde finales del siglo XVII habâ”œÂ¡a sido reconvertido en vivienda. Tras estos edificios circulaba la calle de las Arcadas, en el tramo donde a la izquierda desembocaba la calle de Jusepillo de Olleta. En el momento de tomar esta fotografâ”œÂ¡a se estaba procediendo a urbanizar la calle de Alonso V. Una intervenciâ”œâ”‚n municipal posterior supuso la restauraciâ”œâ”‚n y rehabilitaciâ”œâ”‚n, previo derribo de las viviendas adosadas, de este y otros dos torreones, ademâ”œÃ­s de algunos inmediatos lienzos del tramo de muralla medieval. En este caso la rehabilitaciâ”œâ”‚n del oculto torreâ”œâ”‚n tuvo que ser forzosamente muy creativa.', 1986, 1986, 1986, 'Anos 80', 'CASCO HISTâ”œÃ´RICO', 41.65252900, -0.87143800, '0101000020E610000095BBCFF1D1E2EBBF8658FD1186D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48108411727.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48108411727.webp', 'https://www.flickr.com/photos/zaragozaantigua/48108411727/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23588, 'Calle de Alonso V 1986', 'Imagen capturada en la calle de Alonso V y centrada en el tramo de los inmuebles de los nâ”œâ•‘meros 10-16 (de derecha a izquierda), adosados desde finales del siglo XIX sobre la muralla medieval de ladrillo que delimitaba la ciudad en esta zona, dejando extramuros a la rebolerâ”œÂ¡a, al otro lado de la entonces calle de las Tenerâ”œÂ¡as. El inmueble del nâ”¬â•‘ 16, a la izquierda, se habâ”œÂ¡a construido previo derribo del tercero de los antiguos cubos de la muralla, desde la antigua puerta de la Portaza, luego del Sol. Tras estos edificios circulaba la calle de las Arcadas y el desemboque en la misma de la calle de Jusepillo de Olleta. En el momento de tomar esta fotografâ”œÂ¡a se estaba procediendo a urbanizar la calle de Alonso V. Una intervenciâ”œâ”‚n municipal posterior supuso la restauraciâ”œâ”‚n creativa, previo derribo de las viviendas adosadas, de este tramo de la muralla medieval, y se apuntâ”œâ”‚ la preexistencia del referido y desaparecido cubo de la muralla con una reconstrucciâ”œâ”‚n parcial.', 1986, 1986, 1986, 'Anos 80', 'CASCO HISTâ”œÃ´RICO', 41.65244800, -0.87127800, '0101000020E61000005E2D776682E1EBBF992B836A83D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48114400817.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48114400817.webp', 'https://www.flickr.com/photos/zaragozaantigua/48114400817/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23590, 'Calle de Martâ”œÂ¡n Carrillo 1991', 'Imagen capturada desde cierta altura en el inmueble del nâ”¬â•‘ 5 de la calle del â”œÃ´rgano, y centrada los modernos edificios residenciales que a la izquierda se extienden en esta manzana desde la calle de Torrellas, la plaza de Asso (nâ”¬â•‘ 6) la calle de Martâ”œÂ¡n Carrillo (nâ”¬â•‘ 3, 5 y 7) y hasta la calle de la Universidad. Fueron proyectados por los arquitectos Teâ”œâ”‚filo Martâ”œÂ¡n Sâ”œÃ­enz y Luis Fernâ”œÃ­ndez Ramâ”œÂ¡rez sobre los solares de antiguas casonas en esta parte del barrio de la Magdalena, incluyendo la fotogâ”œÂ®nica Casa Tejada. En primer tâ”œÂ®rmino, aspecto de la calle de Martâ”œÂ¡n Carrillo tras la urbanizaciâ”œâ”‚n integral de esta zona, dotâ”œÃ­ndola de nuevo mobiliario urbano, arbolado, iluminaciâ”œâ”‚n e incluyendo itinerarios peatonales. A la izquierda, las referidas viviendas residenciales aâ”œâ•‘n sin ocupar, y con los bajos comerciales tapiados de obra y aâ”œâ•‘n vacantes. A la derecha, lienzo norteâ”œâ–’o de la iglesia parroquial de Santa Marâ”œÂ¡a Magdalena. Al fondo y a la izquierda, el IES Pedro de Luna, recayente a la plaza de la Magdalena y construido donde estuviera la homâ”œâ”‚nima universidad. Tras el Coso Bajo, vista parcial del solar tras derribo del nâ”¬â•‘ 164, esquinero con la calle de Alejandro Palomar y construido algunos aâ”œâ–’os despuâ”œÂ®s.', 1991, 1991, 1991, 'Anos 90', 'CASCO HISTâ”œÃ´RICO', 41.65269700, -0.87387400, '0101000020E6100000FA635A9BC6F6EBBF429946938BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50262950396.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50262950396.webp', 'https://www.flickr.com/photos/zaragozaantigua/50262950396/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23591, 'Discoteca Flying 1990', 'Terrible matinal del domingo 14 de enero de 1990 tras el incendio en la discoteca Flying sita en la esquina de la calle de Don Teobaldo, desde donde se ha capturado esta imagen, con la de la Trinidad, que por la derecha y hacia el fondo desciende hasta el Coso Bajo. En primer tâ”œÂ®rmino, ingreso al local siniestrado en el que murieron 43 personas, con rastros en la fachada de las tâ”œâ”‚xicas emanaciones causantes de la catâ”œÃ­strofe.', 1990, 1990, 1990, 'Anos 90', 'CASCO HISTâ”œÃ´RICO', 41.65330600, -0.87259700, '0101000020E610000089CE328B50ECEBBFEA23F0879FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50307864071.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50307864071.webp', 'https://www.flickr.com/photos/zaragozaantigua/50307864071/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23593, 'Calle de San Lorenzo 1991', 'Imagen del tramo final de la calle de San Lorenzo, con su tradicional pequeâ”œâ–’o comercio (como "Casa Paco. Novelas-Revistas", a la izquierda) y "aceras" liliputienses, capturada desde el desemboque en el Coso Bajo. Inmediato y a la derecha, vista parcial del gran solar resultante del derribo de los antiguos inmuebles de los nâ”œâ•‘meros 53 y 55 de esta calle y de los nâ”œâ•‘meros 135 y 137 del Coso, refundidos poco tiempo despuâ”œÂ®s en el moderno inmueble del nâ”¬â•‘ 137 del Coso. Hacia el fondo y a la izquierda, Arranque de la calle de los Pelegrâ”œÂ¡n y vista del esquinero inmueble del nâ”¬â•‘ 51 de la calle de San Lorenzo, que a finales de la dâ”œÂ®cada serâ”œÃ­ derribado y sustituido por el actual nâ”¬â•‘ 1 de los Pelegrâ”œÂ¡n.', 1991, 1991, 1991, 'Anos 90', 'CASCO HISTâ”œÃ´RICO', 41.65178300, -0.87377700, '0101000020E61000005CE7DF2EFBF5EBBF5D8B16A06DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50439910588.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50439910588.webp', 'https://www.flickr.com/photos/zaragozaantigua/50439910588/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23594, 'Calle de Aâ”œâ–’â”œâ”‚n 1991', 'Imagen capturada en la calle de Pedro Garcâ”œÂ®s Aâ”œâ–’â”œâ”‚n durante la construcciâ”œâ”‚n, a la derecha, de las 45 viviendas municipales de alquiler levantadas sobre el gran solar dejado tras el derribo de los antiguos inmuebles de los nâ”œâ•‘meros 5-7, 9 y 11-13 de esta calle, ademâ”œÃ­s del nâ”¬â•‘ 5-7 de la calle del Heroâ”œÂ¡smo. El ingreso a las viviendas desde donde se ha realizado la imagen estaba proyectado mediante un gran espacio interior porticado que recibirâ”œÂ¡a el nombre de plaza de Aâ”œâ–’â”œâ”‚n. Esta gran manzana delimitada entre las calles del Heroâ”œÂ¡smo, Cantâ”œÂ¡n y Gamboa, la Torre y Aâ”œâ–’â”œâ”‚n resultâ”œâ”‚ ser rica en restos arqueolâ”œâ”‚gicos que aâ”œâ–’os mâ”œÃ­s tarde, con motivo de nuevas excavaciones en esta â”œâ•‘ltima calle, donde estuvieran los derribados inmuebles nâ”¬â•‘ 21 y 23, revelarâ”œÂ¡an las estructuras arquitectâ”œâ”‚nicas de varias destacadas "domus" romanas de la dinastâ”œÂ¡a Julio-Claudia, abandonadas a finales del siglo I de nuestra era, donde se encontraron los restos del mejor conjunto de bienes muebles y decoraciones domâ”œÂ®sticas de la colonia Caesaraugusta. Al fondo de la imagen, arranque de la calle de Aâ”œâ–’â”œâ”‚n desde la del Heroâ”œÂ¡smo.', 1991, 1991, 1991, 'Anos 90', 'CASCO HISTâ”œÃ´RICO', 41.65070100, -0.87352000, '0101000020E610000087DC0C37E0F3EBBFBC3C9D2B4AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50494632363.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50494632363.webp', 'https://www.flickr.com/photos/zaragozaantigua/50494632363/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23595, 'La Magdalena, 1865', 'Iglesia de Santa Marâ”œÂ¡a Magdalena recreada con el supuesto aspecto que tenâ”œÂ¡a antes de la gran reforma barroca que en 1727-30 reorientâ”œâ”‚ su entrada principal, pasando de la calle Mayor a la antigua cabecera del templo, en la plaza de la Magdalena, y recreciâ”œâ”‚ la original torre con un remate que aquâ”œÂ¡ aparece en color mâ”œÃ­s atenuado y que perdurâ”œâ”‚ hasta que fue eliminado en la rehabilitaciâ”œâ”‚n de 1970. El punto de vista estâ”œÃ­ tomado desde la plaza de la Magdalena, quedando a la izquierda la calle Mayor, y a la derecha la calle de Martâ”œÂ¡n Carrillo. A espaldas quedaba la Puerta de Valencia.', 1865, 1865, 1865, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65235200, -0.87378800, '0101000020E61000005664744012F6EBBF77BD344580D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50880882348.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50880882348.webp', 'https://www.flickr.com/photos/zaragozaantigua/50880882348/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24020, 'Calle Monreal 2002', 'En marzo de 2002 se celebrâ”œâ”‚ en Zaragoza una "reuniâ”œâ”‚n informal" de Ministros de Defensa de la Uniâ”œâ”‚n Europea. El Foro Zaragoza 2002, formado por cerca de 40 asociaciones, convocâ”œâ”‚ un acto antimilitarista ante la puerta de la fâ”œÃ­brica de armas Instalaza, en la calle Monreal 27. Esta empresa, fundada en 1943, "es una compaâ”œâ–’ia de vanguardia que aplica las â”œâ•‘ltimas tecnologâ”œÂ¡as en el diseâ”œâ–’o, desarrollo y fabricaciâ”œâ”‚n de equipos y material para ofrecer soluciones eficaces". Sus productos "equipan a las fuerzas armadas de paâ”œÂ¡ses de todo el mundo, con resultados muy satisfactorios y con un mâ”œÃ­ximo nivel de operatividad y eficacia". Fuente: Agencia EFE.', 2002, 2002, 2002, 'Siglo XXI', 'CASCO HISTâ”œÃ´RICO', 41.65244700, -0.86942200, '0101000020E61000007F880D164ED2EBBFC9AF1F6283D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24629717866.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24629717866.webp', 'https://www.flickr.com/photos/zaragozaantigua/24629717866/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24220, 'Pl. de la Magdalena 1872', 'Dibujo: Pradilla; grabado: Severini. 1872. "Zaragoza. Fiestas del Pilar. Cabalgata histâ”œâ”‚rica de don Jaime el Conquistador." Grabado con la recreaciâ”œâ”‚n histâ”œâ”‚rica de la entrada del rey Jaime I el Conquistador en la ciudad de Valencia el 28 de septiembre de 1238. Esta cabalgata fue incluida en el programa de las Fiestas del Pilar, y en la imagen se adentra en el Coso Bajo proveniente de la calle Mayor. Al fondo, la plaza de la Magdalena. Unos aâ”œâ–’os antes se habâ”œÂ¡a dado el nombre de Don Jaime I a uno de los principales viales de la ciudad. Fuente: "La Ilustraciâ”œâ”‚n Espaâ”œâ–’ola y Americana", Madrid, Aâ”œâ–’o XVI, nâ”¬â•‘ XLII, 08-11-1872.', 1872, 1872, 1872, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65201200, -0.87320400, '0101000020E61000007590D78349F1EBBFBE4C142175D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15283479654.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15283479654.webp', 'https://www.flickr.com/photos/zaragozaantigua/15283479654/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24414, 'Tenerâ”œÂ¡as 1942', 'Imagen de la capilla habilitada en el cuartel del Grupo de Automâ”œâ”‚viles del 5â”¬â•‘ Cuerpo de Ejâ”œÂ®rcito, ubicado desde 1937 en la confluencia de la calle del Asalto, la plaza de las Tenerâ”œÂ¡as, y la ribera del Ebro. Una buena muestra de la abrumadora memoria histâ”œâ”‚rica de la guerra de 1936-39, el perenne homenaje a los muertos durante la Cruzada, y la â”œÂ¡ntima relaciâ”œâ”‚n entre fuerzas armadas, e iglesia catâ”œâ”‚lica. Fuente: Archivo Coyne. AHPZ', 1942, 1942, 1942, 'Anos 40', 'CASCO HISTâ”œÃ´RICO', 41.65370900, -0.87120100, '0101000020E610000087C267EBE0E0EBBFE90C8CBCACD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32796858004.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32796858004.webp', 'https://www.flickr.com/photos/zaragozaantigua/32796858004/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24879, 'Muralla medieval c.1877', 'Archivo RUIZ VERNACCI, Jean Laurent y Câ”œÂ¡a. 1872-1879. Titulado "Torreâ”œâ”‚n del Trovador", se trata de una de las torres de la muralla medieval de râ”œÂ®jola, en la actual calle de Alonso V.', 1877, 1877, 1877, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65237600, -0.87120600, '0101000020E6100000F986C267EBE0EBBFFF58880E81D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14843226426.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14843226426.webp', 'https://www.flickr.com/photos/zaragozaantigua/14843226426/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24911, 'Muralla medieval 2013', 'Foto: Rusolera, abril de 2013. El 6 de abril de 2013 se derrumbâ”œâ”‚ parte del lienzo de la muralla medieval de Zaragoza, entre la calle de Alonso V y la de las Arcadas. Unos 25 metros, que fueron repuestos meses despuâ”œÂ®s. Fuente: zaragozaciudad.net/zaragozafluye/2014/091801-muralla-medi...', 2013, 2013, 2013, 'Siglo XXI', 'CASCO HISTâ”œÃ´RICO', 41.65259200, -0.87125700, '0101000020E610000080272D5C56E1EBBFCCD0782288D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21494516160.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21494516160.webp', 'https://www.flickr.com/photos/zaragozaantigua/21494516160/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25964, 'Colegio San Agustâ”œÂ¡n 1994', 'Tras el desalojo del 23 de diciembre de 1993 de la Casa de la Paz, en el paseo de Sagasta 52, el colectivo de okupas de Zaragoza buscâ”œâ”‚ un nuevo alojamiento en el abandonado colegio de San Agustâ”œÂ¡n, en el nâ”œâ•‘mero 5 de la calle homâ”œâ”‚nima, a principios de 1994, como ilustra la foto. Fueron desalojados en una semana. En mayo de 1996 volvieron a intentarlo.', 1994, 1994, 1994, 'Anos 90', 'CASCO HISTâ”œÃ´RICO', 41.65153900, -0.87181600, '0101000020E6100000292504ABEAE5EBBFC68844A165D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52492136001.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52492136001.webp', 'https://www.flickr.com/photos/zaragozaantigua/52492136001/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20960, 'La Lonja 1858', '"Town Hall Zaragoza". J.B. Waring (dib.) y T.H. Macquoid (lit.), 1858. Colecciâ”œâ”‚n Pascual de Quinto. Vista de la Lonja de Mercaderes de Zaragoza (Juan de Sariâ”œâ–’ena, 1551), desde la plaza de La Seo. A la izquierda del edificio queda la calle del Pilar; a la derecha, la Casa de la Ciudad (antiguo Ayuntamiento), en la ribera del râ”œÂ¡o Ebro; y donde pasa el jinete es la actual calle de Don Jaime I. Fuente: commons.wikimedia.org/wiki/File:Zaragoza_-_La_Lonja.webp', 1858, 1858, 1858, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65566000, -0.87642500, '0101000020E610000096B20C71AC0BECBFCEA5B8AAECD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15498200202.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15498200202.webp', 'https://www.flickr.com/photos/zaragozaantigua/15498200202/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21030, 'Puerta del â”œÃ¼ngel 1860', '"Entrada de SS. MM. en Zaragoza por la puerta del â”œÃ¼ngel el dâ”œÂ¡a 7 de octubre de 1860". Dibujo con la vista desde el interior de la ciudad de la nueva Puerta del â”œÃ¼ngel, construida en el lugar de la anterior con motivo de la visita de la reina Isabel II, el rey consorte Francisco de Asâ”œÂ¡s de Borbâ”œâ”‚n, y los infantes y el heredero al trono, futuro Alfonso XII. A la izquierda, las "casas consistoriales" del viejo ayuntamiento. A la derecha, el edificio del arzobispado en la plaza de la Seo. La puerta estarâ”œÃ­ en pie sâ”œâ”‚lo ocho aâ”œâ–’os. Su exagerada ornamentaciâ”œâ”‚n superior, de materiales efâ”œÂ¡meros, todavâ”œÂ¡a mucho menos. Fuente visual: AMZ', 1860, 1860, 1860, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65590200, -0.87614900, '0101000020E6100000118AADA06909ECBFC4B0C398F4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24331023153.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24331023153.webp', 'https://www.flickr.com/photos/zaragozaantigua/24331023153/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21091, 'La Lonja c.1877', 'Imagen capturada en el interior de la nave-salâ”œâ”‚n de la renacentista Lonja de Mercaderes con una vista transversal orientada hacia el muro oriental y la puerta de ingreso desde la calle de la Lonja. A la izquierda y fuera de plano quedaban las dos puertas que la comunicaban con la anexa Casa Ayuntamiento. Destaca la bâ”œâ”‚veda de crucerâ”œÂ¡a estrellada, las columnas denominadas "aragonesas" por la inserciâ”œâ”‚n de un anillo en su fuste a un tercio de la altura, y la portada ornamentada en relieve y en yeso con el escudo imperial flanqueado por leones. Esta fotografâ”œÂ¡a resulta excepcional ya que posiblemente incluye en ella el posado del fotâ”œâ”‚grafo francâ”œÂ®s Jean Laurent, de blanco y sentado a la izquierda, y su equipo de colaboradores.', 1877, 1877, 1877, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65581500, -0.87657800, '0101000020E61000002D944C4EED0CECBFF59CF4BEF1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52453284748.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52453284748.webp', 'https://www.flickr.com/photos/zaragozaantigua/52453284748/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21113, 'Lonja-Ayuntamiento c.1880', 'Al principio de la antigua calle de la Cuchillerâ”œÂ¡a, otra imagen de la Lonja en tiempos en que era utilizada como espacio para actos pâ”œâ•‘blicos varios, incluyendo el sorteo de "los Quintos" (Servicio Militar Obligatorio para quienes no podâ”œÂ¡an evadirse pagando), y algunas representaciones teatrales. A su derecha, inmediato, la Casa Consistorial en su ubicaciâ”œâ”‚n de siglos y siglos, con el edificio levantado unas dâ”œÂ®cadas antes, con resabios dieciochescos, y puerta principal de acceso arquitrabado y en orden dâ”œâ”‚rico. Fuente visual: Anselmo Marâ”œÂ¡a Coyne, Estudio Coyne (DARA_AHPZ)', 1880, 1880, 1880, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65591300, -0.87633500, '0101000020E610000097E2AAB2EF0AECBFB8020AF5F4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23310046131.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23310046131.webp', 'https://www.flickr.com/photos/zaragozaantigua/23310046131/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21115, 'Calle de la Lonja 1889', 'Fachada principal del renacentista edificio de la Lonja, en una imagen capturada desde la plaza de la Seo. A su izquierda, la calle del Pilar, apenas un callejâ”œâ”‚n antes del derribo de las parcelas de los nâ”œâ•‘meros 36 a 44 accesorio, y la nâ”¬â•‘ 7 de la calle de Don Jaime I. A su derecha, las Casas de la ciudad, o ayuntamiento, y el ingreso desde el puente de Piedra. A pesar de que desde mediados del siglo XIX se acometiâ”œâ”‚ la realineaciâ”œâ”‚n y la unificaciâ”œâ”‚n de los varios nombres que, de toda la vida, tenâ”œÂ¡an los diferentes tramos de la calle Don Jaime I (Nueva de San Gil, Baja de San Pedro, Virgen del Rosario, Cuchillerâ”œÂ¡a), este todavâ”œÂ¡a era denominada "calle de la Lonja", y mâ”œÃ­s tarde "Fernando el Catâ”œâ”‚lico". Mientras el seâ”œâ–’or Max Junghâ”œÃ±ndel preparaba la câ”œÃ­mara para realizar esta imagen, un heterogâ”œÂ®neo grupo de paisanos se ha estacionado en medio, hasta que salga el pajarito. La baja intensidad del trâ”œÃ­fico rodado facilitâ”œâ”‚ un limpio y despejado resultado.', 1889, 1889, 1889, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65550100, -0.87642800, '0101000020E6100000DA8EA9BBB20BECBF66BFEE74E7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25573691181.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25573691181.webp', 'https://www.flickr.com/photos/zaragozaantigua/25573691181/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21219, 'Puente de Piedra c.1900', 'Imagen capturada desde cierta altura del puente de Piedra y el Arrabal. Fuente visual: fototipia Lucas Escolâ”œÃ­, en www.memoriademadrid.es/', 1900, 1900, 1900, 'Anos 1900', 'CASCO HISTâ”œÃ´RICO', 41.65646200, -0.87669800, '0101000020E6100000D6FECEF6E80DECBF8B8862F206D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15672942110.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15672942110.webp', 'https://www.flickr.com/photos/zaragozaantigua/15672942110/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21232, 'Ribera del Ebro c.1900', 'Imagen capturada desde la ribera del Ebro, junto la "Posada del Rey", espacio de confluencia y descanso de carros, carretas, diligencias, ademâ”œÃ­s de las gentes asociadas a estos medios de negocio y transporte. A la izquierda, la verja que delimitaba el palacio de los marqueses de Ayerbe. A la derecha, el puente de Piedra que cruza el Ebro. Al fondo, la iglesia parroquial de Altabâ”œÃ­s, el convento de Santa Isabel, y un macizo torreâ”œâ”‚n del cuartel de San Lâ”œÃ­zaro. Fuente visual: Colecciâ”œâ”‚n Antonio Arguas Perdiguer, en "El libro de oro de Aragâ”œâ”‚n", EPA, 1997.', 1900, 1900, 1900, 'Anos 1900', 'CASCO HISTâ”œÃ´RICO', 41.65625600, -0.87693200, '0101000020E6100000A01B9AB2D30FECBFE2E6543200D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19376659492.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19376659492.webp', 'https://www.flickr.com/photos/zaragozaantigua/19376659492/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21287, 'Seâ”œâ–’oritas 1903', 'Foto: Algora. "Grupo de las seâ”œâ–’oritas que tomaron parte en el concurso de corte organizado por doâ”œâ–’a Pilar del Valle y celebrado como final de las fiestas de la patrona de Zaragoza en la Lonja local de dicha poblaciâ”œâ”‚n". Fuente: Diario ABC, 30-10-1903.', 1903, 1903, 1903, 'Anos 1900', 'CASCO HISTâ”œÃ´RICO', 41.65582800, -0.87663100, '0101000020E6100000E31C75745C0DECBF8AE6012CF2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26075864338.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26075864338.webp', 'https://www.flickr.com/photos/zaragozaantigua/26075864338/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
