INSERT INTO public.photos VALUES (21372, 'La Lonja y el Pilar 1918', 'Una mirada hacia el Oeste desde la torre de La Seo, capturando la calle Don Jaime I y la del Pilar (con las manzanas de viviendas en su entorno), La Lonja, El Pilar y la arbolada plaza de su nombre. Al fondo, tras la clâ”œÂ¡nica del Doctor Palomar y el antiguo palacio de Aytona, la torre y câ”œâ•‘pula de San Juan de los Panetes, y el Torreâ”œâ”‚n de la Zuda. Sobre el Ebro, el puente del Ferrocarril. En la margen izquierda, grandes arboledas, un verdadero bosque de ribera. Fuente: Zaragoza 1908-2008. FCC.', 1918, 1918, 1918, 'Anos 10', 'CASCO HISTâ”œÃ´RICO', 41.65572700, -0.87652800, '0101000020E6100000BCE7C072840CECBF560DC2DCEED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15524839000.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15524839000.webp', 'https://www.flickr.com/photos/zaragozaantigua/15524839000/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
